-- Acts 16 — The Macedonian Call, Lydia, and the Philippian Jailer
-- Theme: The Gospel Crosses into Europe

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 16,
  'Acts 16 opens the second missionary journey''s decisive advance: Paul circumcises Timothy at Lystra for strategic witness, strengthens the churches, and, forbidden by the Holy Spirit to enter Asia or Bithynia, is summoned to Macedonia by a night vision. Landing at Neapolis and proceeding to Philippi — a Roman colony — the apostles meet Lydia by the river; her heart is opened by the Lord and she becomes the first European convert. A slave-girl with a python-spirit is delivered; her owners, losing their profits, drag Paul and Silas before the magistrates, who scourge and imprison them. At midnight the apostles sing, an earthquake shakes the foundations, and the jailer, about to kill himself, is converted with his whole household. The magistrates, learning they have beaten Roman citizens, beg the apostles to depart. The European church is born through sovereign guidance, household conversions, and public vindication of God''s servants.',
  'The Gospel Crosses into Europe',
  'διαβὰς',
  'cross over (diabas) — the Spirit-guided crossing of the gospel from Asia into Europe by way of Macedonia (v.9).',
  '[{"range":"vv.1-5","title":"Timothy Joins the Mission; Churches Strengthened"},{"range":"vv.6-10","title":"The Spirit Forbids; the Macedonian Call"},{"range":"vv.11-15","title":"Lydia: the First European Convert"},{"range":"vv.16-24","title":"The Python-Spirit Cast Out; Paul and Silas Imprisoned"},{"range":"vv.25-34","title":"The Midnight Earthquake and the Jailer''s Salvation"},{"range":"vv.35-40","title":"Roman Citizenship Vindicated; Departure"}]'::jsonb
FROM books b WHERE b.name = 'Acts'
ON CONFLICT (book_id, chapter_number) DO UPDATE SET
  overview = EXCLUDED.overview,
  theme = EXCLUDED.theme,
  key_word_original = EXCLUDED.key_word_original,
  key_word_meaning = EXCLUDED.key_word_meaning,
  outline = EXCLUDED.outline;

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Then came he to Derbe and Lystra: and, behold, a certain disciple was there, named Timotheus, the son of a certain woman, which was a Jewess, and believed; but his father was a Greek:',
      'Κατήντησεν δὲ εἰς Δέρβην καὶ εἰς Λύστραν. καὶ ἰδοὺ μαθητής τις ἦν ἐκεῖ ὀνόματι Τιμόθεος, υἱὸς γυναικὸς Ἰουδαίας πιστῆς, πατρὸς δὲ Ἕλληνος,',
      'Katēntēsen de eis Derbēn kai eis Lystran. kai idou mathētēs tis ēn ekei onomati Timotheos, huios gynaikos Ioudaias pistēs, patros de Hellēnos,',
      'Timothy''s mother is Eunice and grandmother Lois (2 Tim 1:5); both believing Jewish women nurtured him in the Scriptures from childhood (2 Tim 3:15). His Greek father explains why he was uncircumcised.',
      'Godly mothers and grandmothers are often the hidden architects of church leadership. The faith of unbelieving fathers does not quench what believing mothers sow.'),
  (2, 'Which was well reported of by the brethren that were at Lystra and Iconium.',
      'ὃς ἐμαρτυρεῖτο ὑπὸ τῶν ἐν Λύστροις καὶ Ἰκονίῳ ἀδελφῶν.',
      'hos emartyreito hypo tōn en Lystrois kai Ikoniō adelphōn.',
      '"Well reported" (emartyreito) — the Pauline standard for eldership (1 Tim 3:7). Timothy''s reputation extended beyond his home city.',
      'Public testimony by the brethren is a prerequisite for public ministry. The church''s verdict on a man''s character outweighs his own self-assessment.'),
  (3, 'Him would Paul have to go forth with him; and took and circumcised him because of the Jews which were in those quarters: for they knew all that his father was a Greek.',
      'τοῦτον ἠθέλησεν ὁ Παῦλος σὺν αὐτῷ ἐξελθεῖν, καὶ λαβὼν περιέτεμεν αὐτὸν διὰ τοὺς Ἰουδαίους τοὺς ὄντας ἐν τοῖς τόποις ἐκείνοις, ᾔδεισαν γὰρ ἅπαντες ὅτι Ἕλλην ὁ πατὴρ αὐτοῦ ὑπῆρχεν.',
      'touton ēthelēsen ho Paulos syn autō exelthein, kai labōn perietemen auton dia tous Ioudaious tous ontas en tois topois ekeinois, ēdeisan gar hapantes hoti Hellēn ho patēr autou hypērchen.',
      'Strategic, not legal. Paul had just refused to circumcise Titus as a Gentile at Jerusalem (Gal 2:3); here he circumcises Timothy, half-Jewish by his mother, to remove a needless barrier to synagogue witness. "I am made all things to all men" (1 Cor 9:20-22).',
      'Doctrine forbids circumcision as necessary for salvation; mission may accept it as expedient for a hearing. Liberty in Christ uses liberty for the gospel, not against it.'),
  (4, 'And as they went through the cities, they delivered them the decrees for to keep, that were ordained of the apostles and elders which were at Jerusalem.',
      'ὡς δὲ διεπορεύοντο τὰς πόλεις, παρεδίδοσαν αὐτοῖς φυλάσσειν τὰ δόγματα τὰ κεκριμένα ὑπὸ τῶν ἀποστόλων καὶ πρεσβυτέρων τῶν ἐν Ἱεροσολύμοις.',
      'hōs de dieporeuonto tas poleis, paredidosan autois phylassein ta dogmata ta kekrimena hypo tōn apostolōn kai presbyterōn tōn en Hierosolymois.',
      '"Decrees" (dogmata) — the rulings of the Jerusalem Council (ch. 15). Paul actively propagates the conciliar decisions, demonstrating his submission to the church''s ordered authority.',
      'The apostle to the Gentiles honoured decisions made conciliarly at Jerusalem. Rightly ordered church authority is the friend, not enemy, of missionary liberty.'),
  (5, 'And so were the churches established in the faith, and increased in number daily.',
      'αἱ μὲν οὖν ἐκκλησίαι ἐστερεοῦντο τῇ πίστει καὶ ἐπερίσσευον τῷ ἀριθμῷ καθ᾽ ἡμέραν.',
      'hai men oun ekklēsiai estereounto tē pistei kai eperisseuon tō arithmō kath hēmeran.',
      'Double growth — doctrinal stability (estereounto, "made firm") and numerical increase. Luke''s progress reports (cf. 2:47; 9:31; 12:24) mark each phase.',
      'Healthy churches grow simultaneously in depth and in breadth. Doctrinal establishment and evangelistic multiplication are twin fruits of the Spirit.'),
  (6, 'Now when they had gone throughout Phrygia and the region of Galatia, and were forbidden of the Holy Ghost to preach the word in Asia,',
      'Διῆλθον δὲ τὴν Φρυγίαν καὶ Γαλατικὴν χώραν, κωλυθέντες ὑπὸ τοῦ ἁγίου πνεύματος λαλῆσαι τὸν λόγον ἐν τῇ Ἀσίᾳ·',
      'Diēlthon de tēn Phrygian kai Galatikēn chōran, kōlythentes hypo tou hagiou pneumatos lalēsai ton logon en tē Asia;',
      'The Spirit closes doors as well as opens them. "Asia" here is the Roman province on the western Anatolian coast, including Ephesus — which will be opened on the third journey (19:1).',
      'Divine "no" is as much a revelation of Christ''s will as divine "yes." Closed doors prepare for appointed doors.'),
  (7, 'After they were come to Mysia, they assayed to go into Bithynia: but the Spirit suffered them not.',
      'ἐλθόντες δὲ κατὰ τὴν Μυσίαν ἐπείραζον εἰς τὴν Βιθυνίαν πορευθῆναι, καὶ οὐκ εἴασεν αὐτοὺς τὸ πνεῦμα Ἰησοῦ.',
      'elthontes de kata tēn Mysian epeirazon eis tēn Bithynian poreuthēnai, kai ouk eiasen autous to pneuma Iēsou.',
      'The oldest texts read "Spirit of Jesus" (to pneuma Iēsou), a striking Christological witness — the risen Lord guides His mission through His Spirit.',
      'The Spirit of Jesus superintends every step of Christ''s mission. Sovereign restraint is Christly tenderness toward both apostle and appointed flock.'),
  (8, 'And they passing by Mysia came down to Troas.',
      'παρελθόντες δὲ τὴν Μυσίαν κατέβησαν εἰς Τρῳάδα.',
      'parelthontes de tēn Mysian katebēsan eis Trōada.',
      'Troas, a seaport facing Europe across the Aegean, is the last major Asian station. Here Luke may join Paul — the "we" narratives begin in v.10.',
      'Providence funnels servants to exactly the place where the Master''s next word will meet them.'),
  (9, 'And a vision appeared to Paul in the night; There stood a man of Macedonia, and prayed him, saying, Come over into Macedonia, and help us.',
      'καὶ ὅραμα διὰ νυκτὸς τῷ Παύλῳ ὤφθη, ἀνὴρ Μακεδών τις ἑστὼς καὶ παρακαλῶν αὐτὸν καὶ λέγων· Διαβὰς εἰς Μακεδονίαν βοήθησον ἡμῖν.',
      'kai horama dia nyktos tō Paulō ōphthē, anēr Makedōn tis hestōs kai parakalōn auton kai legōn; Diabas eis Makedonian boēthēson hēmin.',
      'The Macedonian call (diabas — "cross over") redraws the map of salvation history: the gospel leaves Asia and enters Europe. "Help us" (boēthēson) is a cry of desperate need answered by sovereign grace.',
      'The West''s gospel heritage began as answer to a midnight plea. The church owes no nation its message as payment; it owes every nation its message as debt (Rom 1:14).'),
  (10, 'And after he had seen the vision, immediately we endeavoured to go into Macedonia, assuredly gathering that the Lord had called us for to preach the gospel unto them.',
      'ὡς δὲ τὸ ὅραμα εἶδεν, εὐθέως ἐζητήσαμεν ἐξελθεῖν εἰς Μακεδονίαν, συμβιβάζοντες ὅτι προσκέκληται ἡμᾶς ὁ θεὸς εὐαγγελίσασθαι αὐτούς.',
      'hōs de to horama eiden, eutheōs ezētēsamen exelthein eis Makedonian, symbibazontes hoti proskeklētai hēmas ho theos euangelisasthai autous.',
      'The first "we" passage begins — Luke is now with the party. Symbibazontes, "joining together" the evidences, is the patient deduction of God''s will from His guidance.',
      'Divine guidance is discerned by assembling revelation, providence, and Spirit-led reasoning. God does not bypass the mind; He informs it.'),
  (11, 'Therefore loosing from Troas, we came with a straight course to Samothracia, and the next day to Neapolis;',
      'Ἀναχθέντες οὖν ἀπὸ Τρῳάδος εὐθυδρομήσαμεν εἰς Σαμοθρᾴκην, τῇ δὲ ἐπιούσῃ εἰς Νέαν Πόλιν,',
      'Anachthentes oun apo Trōados euthydromēsamen eis Samothrakēn, tē de epiousē eis Nean Polin,',
      'Euthydromēsamen, "ran a straight course" — a favourable wind delivered them rapidly. The return voyage later (20:6) took five days against headwinds.',
      'Providence signs its purposes in favourable winds and in favourable laws, in public vindications and in private earthquakes. God prospers what He appoints.'),
  (12, 'And from thence to Philippi, which is the chief city of that part of Macedonia, and a colony: and we were in that city abiding certain days.',
      'κἀκεῖθεν εἰς Φιλίππους, ἥτις ἐστὶν πρώτη τῆς μερίδος Μακεδονίας πόλις, κολωνία. ἦμεν δὲ ἐν αὐτῇ τῇ πόλει διατρίβοντες ἡμέρας τινάς.',
      'kakeithen eis Philippous, hētis estin prōtē tēs meridos Makedonias polis, kolōnia. ēmen de en autē tē polei diatribontes hēmeras tinas.',
      'Philippi was a Roman colony since 42 BC, populated by veterans; inhabitants held Roman citizenship. Paul''s later letter to this church reflects warm memory of its origins.',
      'God chose a Roman military town for Europe''s first church — demonstrating that no stronghold of human empire is fortified against the gospel.'),
  (13, 'And on the sabbath we went out of the city by a river side, where prayer was wont to be made; and we sat down, and spake unto the women which resorted thither.',
      'τῇ τε ἡμέρᾳ τῶν σαββάτων ἐξήλθομεν ἔξω τῆς πόλεως παρὰ ποταμὸν οὗ ἐνομίζομεν προσευχὴν εἶναι, καὶ καθίσαντες ἐλαλοῦμεν ταῖς συνελθούσαις γυναιξίν.',
      'tē te hēmera tōn sabbatōn exēlthomen exō tēs poleōs para potamon hou enomizomen proseuchēn einai, kai kathisantes elaloumen tais synelthousais gynaixin.',
      'No synagogue existed (10 adult Jewish men were required to form one), so Paul found the informal "place of prayer" (proseuchēn) by the Gangites river. Only women had gathered; the gospel comes to them first.',
      'God dignifies Europe''s first converts as women. The gospel honours what the ancient world often despised; grace seeks the humblest lip to plant itself.'),
  (14, 'And a certain woman named Lydia, a seller of purple, of the city of Thyatira, which worshipped God, heard us: whose heart the Lord opened, that she attended unto the things which were spoken of Paul.',
      'καί τις γυνὴ ὀνόματι Λυδία, πορφυρόπωλις πόλεως Θυατείρων σεβομένη τὸν θεόν, ἤκουεν, ἧς ὁ κύριος διήνοιξεν τὴν καρδίαν προσέχειν τοῖς λαλουμένοις ὑπὸ τοῦ Παύλου.',
      'kai tis gynē onomati Lydia, porphyropōlis poleōs Thyateirōn sebomenē ton theon, ēkouen, hēs ho kyrios diēnoixen tēn kardian prosechein tois laloumenois hypo tou Paulou.',
      'Lydia was a Gentile God-fearer (sebomenē), a wealthy trader in purple dye from Thyatira. Diēnoixen, "opened" — the same word used of Jesus opening the disciples'' understanding (Luke 24:45). Regeneration is the Lord''s sovereign work upon the heart, preceding and producing attentive faith.',
      'Salvation begins with God''s unilateral heart-opening. No preacher can pry open a sinner''s heart; only the Lord opens what sin has shut.'),
  (15, 'And when she was baptized, and her household, she besought us, saying, If ye have judged me to be faithful to the Lord, come into my house, and abide there. And she constrained us.',
      'ὡς δὲ ἐβαπτίσθη καὶ ὁ οἶκος αὐτῆς, παρεκάλεσεν λέγουσα· Εἰ κεκρίκατέ με πιστὴν τῷ κυρίῳ εἶναι, εἰσελθόντες εἰς τὸν οἶκόν μου μένετε· καὶ παρεβιάσατο ἡμᾶς.',
      'hōs de ebaptisthē kai ho oikos autēs, parekalesen legousa; Ei kekrikate me pistēn tō kyriō einai, eiselthontes eis ton oikon mou menete; kai parebiasato hēmas.',
      'Household baptism follows conversion (cf. 16:33; 18:8). Parebiasato, "constrained," is urgent insistence — the first fruit of grace is eager hospitality.',
      'Conversion reorders the home. Grace always expresses itself in open doors, opened purses, and a hospitality bent on sheltering Christ''s servants.'),
  (16, 'And it came to pass, as we went to prayer, a certain damsel possessed with a spirit of divination met us, which brought her masters much gain by soothsaying:',
      'Ἐγένετο δὲ πορευομένων ἡμῶν εἰς τὴν προσευχὴν παιδίσκην τινὰ ἔχουσαν πνεῦμα πύθωνα ὑπαντῆσαι ἡμῖν, ἥτις ἐργασίαν πολλὴν παρεῖχεν τοῖς κυρίοις αὐτῆς μαντευομένη.',
      'Egeneto de poreuomenōn hēmōn eis tēn proseuchēn paidiskēn tina echousan pneuma pythōna hypantēsai hēmin, hētis ergasian pollēn pareichen tois kyriois autēs manteuomenē.',
      'Pythōna — the python-spirit of the Delphic oracle, linked to Apollo. Pagan divination is consistently traced by Scripture to demonic sources (Deut 18:10-12; 1 Cor 10:20).',
      'Occult powers are real, unclean, and enslaving. The gospel confronts them not by negotiation but by expulsion in Christ''s name.'),
  (17, 'The same followed Paul and us, and cried, saying, These men are the servants of the most high God, which shew unto us the way of salvation.',
      'αὕτη κατακολουθοῦσα τῷ Παύλῳ καὶ ἡμῖν ἔκραζεν λέγουσα· Οὗτοι οἱ ἄνθρωποι δοῦλοι τοῦ θεοῦ τοῦ ὑψίστου εἰσίν, οἵτινες καταγγέλλουσιν ὑμῖν ὁδὸν σωτηρίας.',
      'hautē katakolouthousa tō Paulō kai hēmin ekrazen legousa; Houtoi hoi anthrōpoi douloi tou theou tou hypsistou eisin, hoitines katangellousin hymin hodon sōtērias.',
      'Demonic testimony can be factually accurate yet morally corrupt (cf. Mark 1:24-25). Paul refuses Satan''s advertising as Jesus refused the demons''.',
      'The gospel does not need the endorsement of Satan''s mouthpieces. Truth advertised by devils is still devilish; Christ''s witnesses are a church-made voice.'),
  (18, 'And this did she many days. But Paul, being grieved, turned and said to the spirit, I command thee in the name of Jesus Christ to come out of her. And he came out the same hour.',
      'τοῦτο δὲ ἐποίει ἐπὶ πολλὰς ἡμέρας. διαπονηθεὶς δὲ Παῦλος καὶ ἐπιστρέψας τῷ πνεύματι εἶπεν· Παραγγέλλω σοι ἐν ὀνόματι Ἰησοῦ Χριστοῦ ἐξελθεῖν ἀπ᾽ αὐτῆς· καὶ ἐξῆλθεν αὐτῇ τῇ ὥρᾳ.',
      'touto de epoiei epi pollas hēmeras. diaponētheis de Paulos kai epistrepsas tō pneumati eipen; Parangellō soi en onomati Iēsou Christou exelthein ap autēs; kai exēlthen autē tē hōra.',
      'Diaponētheis, "being distressed/annoyed through and through," marks Paul''s moral burden. The exorcism is instantaneous — "the same hour."',
      'Christ''s name, on the lips of His servants, routs the strongest demons. Authority belongs to the Name, not the man who names it.'),
  (19, 'And when her masters saw that the hope of their gains was gone, they caught Paul and Silas, and drew them into the marketplace unto the rulers,',
      'ἰδόντες δὲ οἱ κύριοι αὐτῆς ὅτι ἐξῆλθεν ἡ ἐλπὶς τῆς ἐργασίας αὐτῶν, ἐπιλαβόμενοι τὸν Παῦλον καὶ τὸν Σιλᾶν εἵλκυσαν εἰς τὴν ἀγορὰν ἐπὶ τοὺς ἄρχοντας,',
      'idontes de hoi kyrioi autēs hoti exēlthen hē elpis tēs ergasias autōn, epilabomenoi ton Paulon kai ton Silan heilkysan eis tēn agoran epi tous archontas,',
      'The motive is purely commercial — idolatry and avarice conspire wherever the gospel threatens exploitation. Note "hope of their gains was gone": Christ dethrones mammon by delivering its victims.',
      'The gospel threatens any economic system built on human bondage. Where Christ reigns, false markets collapse.'),
  (20, 'And brought them to the magistrates, saying, These men, being Jews, do exceedingly trouble our city,',
      'καὶ προσαγαγόντες αὐτοὺς τοῖς στρατηγοῖς εἶπαν· Οὗτοι οἱ ἄνθρωποι ἐκταράσσουσιν ἡμῶν τὴν πόλιν Ἰουδαῖοι ὑπάρχοντες,',
      'kai prosagagontes autous tois stratēgois eipan; Houtoi hoi anthrōpoi ektarassousin hēmōn tēn polin Ioudaioi hyparchontes,',
      'Stratēgoi (literally "generals") — the Roman duoviri who governed the colony. The accusation exploits Roman suspicion of Jewish agitators (cf. Claudius''s expulsion, 18:2).',
      'Gospel faithfulness often meets false charges dressed as patriotism. Satan accuses with political pretext where he cannot refute with truth.'),
  (21, 'And teach customs, which are not lawful for us to receive, neither to observe, being Romans.',
      'καὶ καταγγέλλουσιν ἔθη ἃ οὐκ ἔξεστιν ἡμῖν παραδέχεσθαι οὐδὲ ποιεῖν Ῥωμαίοις οὖσιν.',
      'kai katangellousin ethē ha ouk exestin hēmin paradechesthai oude poiein Rhōmaiois ousin.',
      'Roman citizens were technically forbidden to adopt foreign religions that undermined state cult. The charge, though exaggerated, had legal teeth in a colony.',
      'The world often makes Christian loyalty appear a political liability. Yet Christ''s true subjects are the safest citizens of every commonwealth.'),
  (22, 'And the multitude rose up together against them: and the magistrates rent off their clothes, and commanded to beat them.',
      'καὶ συνεπέστη ὁ ὄχλος κατ᾽ αὐτῶν, καὶ οἱ στρατηγοὶ περιρήξαντες αὐτῶν τὰ ἱμάτια ἐκέλευον ῥαβδίζειν,',
      'kai synepestē ho ochlos kat autōn, kai hoi stratēgoi perirēxantes autōn ta himatia ekeleuon rhabdizein,',
      'Rhabdizein is the Roman flogging with rods, carried out by lictors. Paul alludes to this in 2 Cor 11:25 ("thrice was I beaten with rods"). The magistrates acted without due process.',
      'Where mob passion rules, justice is trampled. The Lord permits His servants to suffer even institutional miscarriage to magnify His name.'),
  (23, 'And when they had laid many stripes upon them, they cast them into prison, charging the jailor to keep them safely:',
      'πολλάς τε ἐπιθέντες αὐτοῖς πληγὰς ἔβαλον εἰς φυλακήν, παραγγείλαντες τῷ δεσμοφύλακι ἀσφαλῶς τηρεῖν αὐτούς.',
      'pollas te epithentes autois plēgas ebalon eis phylakēn, parangeilantes tō desmophylaki asphalōs tērein autous.',
      '"Many stripes" — no legal limit. The wounds would be untreated; their backs would be raw when cast into the inner cell.',
      'The Christian is sometimes delivered from suffering, sometimes delivered through it. Either way the Lord is exalted.'),
  (24, 'Who, having received such a charge, thrust them into the inner prison, and made their feet fast in the stocks.',
      'ὃς παραγγελίαν τοιαύτην λαβὼν ἔβαλεν αὐτοὺς εἰς τὴν ἐσωτέραν φυλακὴν καὶ τοὺς πόδας ἠσφαλίσατο αὐτῶν εἰς τὸ ξύλον.',
      'hos parangelian toiautēn labōn ebalen autous eis tēn esōteran phylakēn kai tous podas ēsphalisato autōn eis to xylon.',
      'The inner prison was typically windowless and damp. Xylon (wooden stocks) forced the legs painfully apart. This is the cruel night that becomes a singing night.',
      'No darkness is dark enough to quench the hymn of faith. The inner prison becomes the outer concert-hall of praise.'),
  (25, 'And at midnight Paul and Silas prayed, and sang praises unto God: and the prisoners heard them.',
      'Κατὰ δὲ τὸ μεσονύκτιον Παῦλος καὶ Σιλᾶς προσευχόμενοι ὕμνουν τὸν θεόν, ἐπηκροῶντο δὲ αὐτῶν οἱ δέσμιοι·',
      'Kata de to mesonyktion Paulos kai Silas proseuchomenoi hymnoun ton theon, epēkroōnto de autōn hoi desmioi;',
      'Hymnoun, "hymning" — formal praise, perhaps psalms. Epēkroōnto, "listened attentively," suggests rapt silence rather than mere overhearing; the prisoners had never heard music in a dungeon before.',
      'Midnight worship in bonds is a sharper sermon than daylight eloquence from pulpits. Suffering saints singing to God evangelize those who cannot yet speak His name.'),
  (26, 'And suddenly there was a great earthquake, so that the foundations of the prison were shaken: and immediately all the doors were opened, and every one''s bands were loosed.',
      'ἄφνω δὲ σεισμὸς ἐγένετο μέγας ὥστε σαλευθῆναι τὰ θεμέλια τοῦ δεσμωτηρίου, ἠνεῴχθησαν δὲ παραχρῆμα αἱ θύραι πᾶσαι, καὶ πάντων τὰ δεσμὰ ἀνέθη.',
      'aphnō de seismos egeneto megas hōste saleuthēnai ta themelia tou desmōtēriou, ēneōchthēsan de parachrēma hai thyrai pasai, kai pantōn ta desma anethē.',
      'The earthquake is selectively miraculous — doors opened, chains loosed, yet no one fled (v.28). This is the finger of God, not geology alone.',
      'God shakes the foundations of prisons to free His people and reach His lost. Natural forces obey the prayers of saints.'),
  (27, 'And the keeper of the prison awaking out of his sleep, and seeing the prison doors open, he drew out his sword, and would have killed himself, supposing that the prisoners had been fled.',
      'ἔξυπνος δὲ γενόμενος ὁ δεσμοφύλαξ καὶ ἰδὼν ἀνεῳγμένας τὰς θύρας τῆς φυλακῆς, σπασάμενος τὴν μάχαιραν ἤμελλεν ἑαυτὸν ἀναιρεῖν, νομίζων ἐκπεφευγέναι τοὺς δεσμίους.',
      'exypnos de genomenos ho desmophylax kai idōn aneōgmenas tas thyras tēs phylakēs, spasamenos tēn machairan ēmellen heauton anairein, nomizōn ekpepheugenai tous desmious.',
      'A Roman soldier who lost prisoners forfeited his own life (cf. 12:19). Suicide seemed honour. In this moment of terror the gospel arrives.',
      'Despair is the doorway through which grace often walks. God brings men to the edge of self-destruction that He may save them by His Son.'),
  (28, 'But Paul cried with a loud voice, saying, Do thyself no harm: for we are all here.',
      'ἐφώνησεν δὲ μεγάλῃ φωνῇ ὁ Παῦλος λέγων· Μηδὲν πράξῃς σεαυτῷ κακόν, ἅπαντες γάρ ἐσμεν ἐνθάδε.',
      'ephōnēsen de megalē phōnē ho Paulos legōn; Mēden praxēs seautō kakon, hapantes gar esmen enthade.',
      'Paul''s first words to a dying man: "Do thyself no harm." The apostle''s concern is not his own freedom but the jailer''s life.',
      'Christian mercy stays escape for the sake of a hostile stranger. The gospel so turns men that they love their enemies more than their own liberty.'),
  (29, 'Then he called for a light, and sprang in, and came trembling, and fell down before Paul and Silas,',
      'αἰτήσας δὲ φῶτα εἰσεπήδησεν καὶ ἔντρομος γενόμενος προσέπεσεν τῷ Παύλῳ καὶ τῷ Σιλᾷ,',
      'aitēsas de phōta eisepēdēsen kai entromos genomenos prosepesen tō Paulō kai tō Sila,',
      'The jailer, who hours before had thrust them into stocks, now trembles at their feet. Eisepēdēsen, "leaped in" — urgency of awakened conscience.',
      'Awakened sinners do not saunter to Christ; they fall at His feet. Trembling is the right posture before holiness.'),
  (30, 'And brought them out, and said, Sirs, what must I do to be saved?',
      'καὶ προαγαγὼν αὐτοὺς ἔξω ἔφη· Κύριοι, τί με δεῖ ποιεῖν ἵνα σωθῶ;',
      'kai proagagōn autous exō ephē; Kyrioi, ti me dei poiein hina sōthō;',
      'The quintessential seeker''s question. He already knows he needs salvation — the earthquake has shaken more than the walls.',
      'When the Spirit convicts, the question is no longer "is there a God?" but "what must I do to be saved?" God answers that question with the gospel.'),
  (31, 'And they said, Believe on the Lord Jesus Christ, and thou shalt be saved, and thy house.',
      'οἱ δὲ εἶπαν· Πίστευσον ἐπὶ τὸν κύριον Ἰησοῦν, καὶ σωθήσῃ σὺ καὶ ὁ οἶκός σου.',
      'hoi de eipan; Pisteuson epi ton kyrion Iēsoun, kai sōthēsē sy kai ho oikos sou.',
      'The NT''s simplest gospel summary. Pisteuson ("believe") is aorist imperative — decisive trust. The promise extends to the whole household on condition of their own believing (cf. v.34).',
      'Salvation is by faith alone in Christ alone. Believing is the only "must" for the sinner; Christ is the only object; household blessing follows household faith.'),
  (32, 'And they spake unto him the word of the Lord, and to all that were in his house.',
      'καὶ ἐλάλησαν αὐτῷ τὸν λόγον τοῦ κυρίου σὺν πᾶσιν τοῖς ἐν τῇ οἰκίᾳ αὐτοῦ.',
      'kai elalēsan autō ton logon tou kyriou syn pasin tois en tē oikia autou.',
      'Faith is not a blind leap; it is grounded in "the word of the Lord" explained to the household. Preaching follows the call to believe.',
      'True conversion requires true teaching. The household must hear what it is to trust before it can trust what it has heard.'),
  (33, 'And he took them the same hour of the night, and washed their stripes; and was baptized, he and all his, straightway.',
      'καὶ παραλαβὼν αὐτοὺς ἐν ἐκείνῃ τῇ ὥρᾳ τῆς νυκτὸς ἔλουσεν ἀπὸ τῶν πληγῶν, καὶ ἐβαπτίσθη αὐτὸς καὶ οἱ αὐτοῦ πάντες παραχρῆμα,',
      'kai paralabōn autous en ekeinē tē hōra tēs nyktos elousen apo tōn plēgōn, kai ebaptisthē autos kai hoi autou pantes parachrēma,',
      'A double washing: the jailer washes the apostles'' wounds, then is himself washed in baptism. Mercy and sacrament in the same midnight hour.',
      'Conversion yields immediate obedience. The new convert tends the wounds he once inflicted, and submits to the sign Christ commanded.'),
  (34, 'And when he had brought them into his house, he set meat before them, and rejoiced, believing in God with all his house.',
      'ἀναγαγών τε αὐτοὺς εἰς τὸν οἶκον παρέθηκεν τράπεζαν, καὶ ἠγαλλιάσατο πανοικεὶ πεπιστευκὼς τῷ θεῷ.',
      'anagagōn te autous eis ton oikon parethēken trapezan, kai ēgalliasato panoikei pepisteukōs tō theō.',
      'Panoikei, "with the whole household," and pepisteukōs, perfect participle — settled faith. Each member believed; each member rejoiced.',
      'Saving faith begets household joy. Grace transforms a Roman jail-keeper''s dinner table into a scene of Eucharistic delight.'),
  (35, 'And when it was day, the magistrates sent the serjeants, saying, Let those men go.',
      'Ἡμέρας δὲ γενομένης ἀπέστειλαν οἱ στρατηγοὶ τοὺς ῥαβδούχους λέγοντες· Ἀπόλυσον τοὺς ἀνθρώπους ἐκείνους.',
      'Hēmeras de genomenēs apesteilan hoi stratēgoi tous rhabdouchous legontes; Apolyson tous anthrōpous ekeinous.',
      'Perhaps the earthquake gave the magistrates second thoughts, or perhaps news of their illegal beating reached them. Either way, providence is arranging Paul''s vindication.',
      'Unjust rulers cannot resist the hand of God that overrules even their panic for His servants'' dignity.'),
  (36, 'And the keeper of the prison told this saying to Paul, The magistrates have sent to let you go: now therefore depart, and go in peace.',
      'ἀπήγγειλεν δὲ ὁ δεσμοφύλαξ τοὺς λόγους τούτους πρὸς τὸν Παῦλον ὅτι Ἀπέσταλκαν οἱ στρατηγοὶ ἵνα ἀπολυθῆτε· νῦν οὖν ἐξελθόντες πορεύεσθε ἐν εἰρήνῃ.',
      'apēngeilen de ho desmophylax tous logous toutous pros ton Paulon hoti Apestalkan hoi stratēgoi hina apolythēte; nyn oun exelthontes poreuesthe en eirēnē.',
      'The now-believing jailer happily reports freedom. "Go in peace" carries a gospel edge: the jailer blesses those he once chained.',
      'The transformed heart blesses those it once bound. Grace reverses relational polarity.'),
  (37, 'But Paul said unto them, They have beaten us openly uncondemned, being Romans, and have cast us into prison; and now do they thrust us out privily? nay verily; but let them come themselves and fetch us out.',
      'ὁ δὲ Παῦλος ἔφη πρὸς αὐτούς· Δείραντες ἡμᾶς δημοσίᾳ ἀκατακρίτους, ἀνθρώπους Ῥωμαίους ὑπάρχοντας, ἔβαλαν εἰς φυλακήν· καὶ νῦν λάθρᾳ ἡμᾶς ἐκβάλλουσιν; οὐ γάρ, ἀλλὰ ἐλθόντες αὐτοὶ ἡμᾶς ἐξαγαγέτωσαν.',
      'ho de Paulos ephē pros autous; Deirantes hēmas dēmosia akatakritous, anthrōpous Rhōmaious hyparchontas, ebalan eis phylakēn; kai nyn lathra hēmas ekballousin? ou gar, alla elthontes autoi hēmas exagagetōsan.',
      'Roman citizens could not lawfully be beaten untried (Lex Porcia, Lex Valeria). Paul insists on public vindication, not for personal vengeance, but for the young church''s future safety.',
      'Christian humility does not surrender Christian rights when the gospel''s future is at stake. Use the law to protect the flock you leave behind.'),
  (38, 'And the serjeants told these words unto the magistrates: and they feared, when they heard that they were Romans.',
      'ἀπήγγειλαν δὲ τοῖς στρατηγοῖς οἱ ῥαβδοῦχοι τὰ ῥήματα ταῦτα· ἐφοβήθησαν δὲ ἀκούσαντες ὅτι Ῥωμαῖοί εἰσιν,',
      'apēngeilan de tois stratēgois hoi rhabdouchoi ta rhēmata tauta; ephobēthēsan de akousantes hoti Rhōmaioi eisin,',
      'Magistrates who flog Roman citizens without trial risk their careers. The tables are turned.',
      'The civil sword is in God''s hand, bent by Him to protect the Christian witness when and where He pleases.'),
  (39, 'And they came and besought them, and brought them out, and desired them to depart out of the city.',
      'καὶ ἐλθόντες παρεκάλεσαν αὐτούς, καὶ ἐξαγαγόντες ἠρώτων ἀπελθεῖν ἀπὸ τῆς πόλεως.',
      'kai elthontes parekalesan autous, kai exagagontes ērōtōn apelthein apo tēs poleōs.',
      'The magistrates now "beseech" the apostles — the reversal is complete. Yet they still ask them to leave, fearing further disturbance.',
      'Public vindication of Christ''s servants is often followed by polite ejection. The world will apologize and still ask the gospel to move along.'),
  (40, 'And they went out of the prison, and entered into the house of Lydia: and when they had seen the brethren, they comforted them, and departed.',
      'ἐξελθόντες δὲ ἀπὸ τῆς φυλακῆς εἰσῆλθον πρὸς τὴν Λυδίαν, καὶ ἰδόντες τοὺς ἀδελφοὺς παρεκάλεσαν αὐτοὺς καὶ ἐξῆλθαν.',
      'exelthontes de apo tēs phylakēs eisēlthon pros tēn Lydian, kai idontes tous adelphous parekalesan autous kai exēlthan.',
      'The apostles, far from being intimidated, stop at Lydia''s house to strengthen the newborn church. Luke apparently stays (the "we" passages pause until 20:5), possibly remaining as pastor at Philippi.',
      'A young church left behind is tenderly catechized. The apostle''s last act before departure is encouragement, not complaint.')
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Acts' AND c.chapter_number = 16
ON CONFLICT (chapter_id, verse_number) DO UPDATE SET
  kjv_text = EXCLUDED.kjv_text,
  original_text = EXCLUDED.original_text,
  transliteration = EXCLUDED.transliteration,
  study_note = EXCLUDED.study_note,
  doctrinal_note = EXCLUDED.doctrinal_note;

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Τιμόθεος', 'Timotheos', 'G5095', 'Timothy — "honouring God"; Paul''s dearly loved spiritual son (1 Tim 1:2).', 1),
  (2, 'ἐμαρτυρεῖτο', 'emartyreito', 'G3140', 'Was well-reported-of — the Pauline standard for eldership (1 Tim 3:7).', 2),
  (3, 'περιέτεμεν', 'perietemen', 'G4059', 'He circumcised — here done strategically for mission, not for salvation.', 3),
  (4, 'δόγματα', 'dogmata', 'G1378', 'Decrees, ordinances — the Jerusalem Council''s conciliar rulings.', 4),
  (5, 'ἐστερεοῦντο', 'estereounto', 'G4732', 'Were made firm — doctrinal stability of churches.', 5),
  (6, 'κωλυθέντες', 'kōlythentes', 'G2967', 'Having been forbidden/hindered — Spirit-given closed doors.', 6),
  (7, 'πνεῦμα Ἰησοῦ', 'pneuma Iēsou', 'G4151/G2424', 'Spirit of Jesus — the risen Lord''s Spirit directing His mission.', 7),
  (9, 'ὅραμα', 'horama', 'G3705', 'Vision — a supernatural sight granted for specific guidance.', 8),
  (9, 'Διαβὰς', 'Diabas', 'G1224', 'Crossing over — the keyword of the chapter; gospel crossing from Asia to Europe.', 9),
  (9, 'βοήθησον', 'boēthēson', 'G997', 'Help! — a cry of desperate need, met by sovereign mission.', 10),
  (10, 'συμβιβάζοντες', 'symbibazontes', 'G4822', 'Joining together, concluding — the Spirit-led reasoning that confirms God''s call.', 11),
  (11, 'εὐθυδρομήσαμεν', 'euthydromēsamen', 'G2113', 'Ran a straight course — favourable sailing wind as providential confirmation.', 12),
  (12, 'κολωνία', 'kolōnia', 'G2862', 'Colony — Roman military colony with citizen status.', 13),
  (13, 'προσευχὴν', 'proseuchēn', 'G4335', 'Place of prayer — informal Jewish meeting where no synagogue existed.', 14),
  (14, 'πορφυρόπωλις', 'porphyropōlis', 'G4211', 'Seller of purple — wealthy trader in expensive dyed cloth.', 15),
  (14, 'σεβομένη τὸν θεόν', 'sebomenē ton theon', 'G4576/G2316', 'Worshipper of God — technical term for Gentile God-fearer attached to synagogue.', 16),
  (14, 'διήνοιξεν', 'diēnoixen', 'G1272', 'Opened thoroughly — sovereign regeneration (same verb Luke 24:45).', 17),
  (15, 'παρεβιάσατο', 'parebiasato', 'G3849', 'Constrained, urgently pressed — hospitality as evidence of conversion.', 18),
  (16, 'πύθωνα', 'pythōna', 'G4436', 'Python — the Delphic oracle spirit, demonic divination source.', 19),
  (16, 'μαντευομένη', 'manteuomenē', 'G3132', 'Soothsaying, practising divination — forbidden occult activity (Deut 18:10).', 20),
  (17, 'ὑψίστου', 'hypsistou', 'G5310', 'Most High — divine title, here used by demon with accurate but unwelcome testimony.', 21),
  (18, 'διαπονηθεὶς', 'diaponētheis', 'G1278', 'Being greatly distressed — moral burden leading to exorcism.', 22),
  (18, 'Παραγγέλλω', 'Parangellō', 'G3853', 'I command/charge — authoritative apostolic order in Christ''s name.', 23),
  (19, 'ἐργασίας', 'ergasias', 'G2039', 'Gain, profit-making — commercial exploitation of bondage.', 24),
  (20, 'στρατηγοῖς', 'stratēgois', 'G4755', 'Magistrates (duoviri) — chief civic officials of a Roman colony.', 25),
  (22, 'ῥαβδίζειν', 'rhabdizein', 'G4463', 'To beat with rods — Roman punishment by lictors (2 Cor 11:25).', 26),
  (24, 'ἐσωτέραν φυλακὴν', 'esōteran phylakēn', 'G2082/G5438', 'Inner prison — the deepest, most secure cell, typically windowless.', 27),
  (24, 'ξύλον', 'xylon', 'G3586', 'Wood, stocks — instrument of painful restraint forcing legs apart.', 28),
  (25, 'ὕμνουν', 'hymnoun', 'G5214', 'Were hymning — formal praise-singing in the inner dungeon.', 29),
  (25, 'ἐπηκροῶντο', 'epēkroōnto', 'G1874', 'Were listening attentively — the prisoners held rapt by midnight worship.', 30),
  (26, 'σεισμὸς', 'seismos', 'G4578', 'Earthquake — selectively miraculous, opening only what mission required.', 31),
  (27, 'ἀναιρεῖν', 'anairein', 'G337', 'To kill, make away with — despair driving the jailer to suicide.', 32),
  (29, 'ἔντρομος', 'entromos', 'G1790', 'Trembling — physical response of awakened conscience before God.', 33),
  (30, 'σωθῶ', 'sōthō', 'G4982', 'I may be saved — aorist subjunctive; decisive deliverance sought.', 34),
  (31, 'Πίστευσον', 'Pisteuson', 'G4100', 'Believe! — aorist imperative; decisive trust in the Lord Jesus.', 35),
  (31, 'κύριον Ἰησοῦν', 'kyrion Iēsoun', 'G2962/G2424', 'Lord Jesus — the object of saving faith; divine sovereign and Saviour.', 36),
  (33, 'ἔλουσεν', 'elousen', 'G3068', 'He washed — tending the very wounds he had inflicted; evidence of conversion.', 37),
  (33, 'ἐβαπτίσθη', 'ebaptisthē', 'G907', 'He was baptized — immediate obedience to Christ''s command.', 38),
  (34, 'ἠγαλλιάσατο', 'ēgalliasato', 'G21', 'Rejoiced greatly — eschatological joy bursting into a midnight home.', 39),
  (34, 'πανοικεὶ', 'panoikei', 'G3832', 'With the whole household — household solidarity of faith and joy.', 40),
  (37, 'Ῥωμαίους', 'Rhōmaious', 'G4514', 'Romans — citizens protected by Lex Porcia from unjust flogging.', 41),
  (37, 'ἀκατακρίτους', 'akatakritous', 'G178', 'Uncondemned — beaten without trial, a grave legal violation.', 42),
  (38, 'ἐφοβήθησαν', 'ephobēthēsan', 'G5399', 'They feared — magistrates terrified of imperial consequences.', 43)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Acts' AND c.chapter_number = 16 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

